     else

before_code:
module ripple_counter(
  input clk,
  input rst_n,
  output reg [15:0] count
);
  always @(posedge clk) begin
    if (!rst_n)
      count <= 16'b0;
    else
      count <= count + 1;
  end
endmodule

after_code:
module ripple_counter(
  input clk,
  input rst_n,
  output reg [15:0] count
);
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
      count <= 16'b0;
    else
      count <= count + 1;
  end
endmodule
